return items.map(item => {
  const dados = item.json;

  // Nome: limpar caracteres estranhos e capitalizar
  let nome = dados.nome_completo || '';
  nome = nome.replace(/[^a-zA-ZÀ-ÿ\s]/g, ' ');
  nome = nome.toLowerCase().trim();
  nome = nome
    .split(/\s+/)
    .map(p => p.charAt(0).toUpperCase() + p.slice(1))
    .join(' ');

  // Telefone: só números
  let telefone = dados.telefone || '';
  telefone = telefone.replace(/\D/g, '');

  // Data: DD/MM/YYYY -> YYYY-MM-DD
  let dataBr = dados.data_nascimento || '';
  const partes = dataBr.split('/');
  let dataIso = null;
  if (partes.length === 3) {
    const [dia, mes, ano] = partes;
    dataIso = `${ano}-${mes}-${dia}`;
  }

  // Curso: normalizar Tech/Business
  let curso = (dados.curso || '').trim().toLowerCase();
  if (curso === 'tech') curso = 'Tech';
  else if (curso === 'business') curso = 'Business';

  item.json = {
    nome: nome,
    email: dados.email,
    data_nascimento: dataIso,
    telefone: telefone,
    curso: curso
  };

  return item;
});
